const express = require('express');
const winston = require('winston');
const { combine, timestamp, json, errors, printf } = winston.format;
const fs = require('fs');
const path = require('path');

// Ensure log directory exists
const logDirectory = path.join(__dirname, 'logs');
if (!fs.existsSync(logDirectory)) {
  fs.mkdirSync(logDirectory);
}

// Initialize Winston Logger
const logger = winston.createLogger({
  level: 'info',
  format: combine(
    errors({ stack: true }), // Log errors with stack trace
    timestamp({
      format: 'YYYY-MM-DD HH:mm:ss',
    }),
    json() // Use JSON format for structured logging
  ),
  transports: [
    // Console transport for development output
    new winston.transports.Console({
      level: 'debug', // Console will show everything from debug up
      format: combine(
        timestamp({
          format: 'YYYY-MM-DD HH:mm:ss',
        }),
        errors({ stack: true }),
        printf(({ level, message, timestamp, stack, ...metadata }) => {
          let msg = `${timestamp} ${level}: ${message}`;
          if (stack) {
            msg += `\n${stack}`;
          }
          if (Object.keys(metadata).length > 0) {
            msg += `\n${JSON.stringify(metadata, null, 2)}`;
          }
          return msg;
        })
      ),
    }),
    // File transport for audit logs
    new winston.transports.File({
      filename: path.join(logDirectory, 'audit.log'),
      level: 'info', // Audit file will show everything from info up
      maxsize: 5242880, // 5MB
      maxFiles: 5,
      tailable: true,
      format: combine(
        errors({ stack: true }),
        timestamp({
          format: 'YYYY-MM-DD HH:mm:ss',
        }),
        json()
      ),
    }),
  ],
  // Handle uncaught exceptions and unhandled promise rejections
  exceptionHandlers: [
    new winston.transports.File({ filename: path.join(logDirectory, 'exceptions.log') }),
  ],
  rejectionHandlers: [
    new winston.transports.File({ filename: path.join(logDirectory, 'rejections.log') }),
  ],
});


const app = express();
app.use(express.json()); // Enable parsing JSON bodies

// Custom Request Logging Middleware
app.use((req, res, next) => {
  const startHrTime = process.hrtime();

  res.on('finish', () => {
    const elapsedHrTime = process.hrtime(startHrTime);
    const elapsedTimeInMs = elapsedHrTime[0] * 1000 + elapsedHrTime[1] / 1e6;

    // Extract user-provided data from headers or other sources
    const username = req.headers['x-username'] || 'anonymous'; // Example: Get username from custom header
    const requestId = req.headers['x-request-id'] || 'N/A'; // Example: Get request ID from custom header
    const customHeader1 = req.headers['x-custom-data-1'] || 'N/A'; // Example: Another custom header

    // Log HTTP request details including user-provided data
    logger.info('HTTP Request', {
      method: req.method,
      url: req.url,
      statusCode: res.statusCode,
      responseTime: `${elapsedTimeInMs.toFixed(3)}ms`,
      ip: req.ip,
      username: username,
      requestId: requestId,
      customHeader1: customHeader1,
      // WARNING: Logging request body or query parameters directly can expose sensitive data.
      // Consider sanitizing or redacting sensitive fields if included.
      // body: req.body,
      // query: req.query
    });
  });

  next();
});

// Endpoint to accept user input and write it to log files (as structured log entries)
// IMPORTANT: This logs user-provided data AS PART OF A STRUCTURED LOG MESSAGE,
//            NOT as raw, unescaped input written directly into a file without context.
//            This approach is crucial for security, maintainability, and auditability.
app.post('/audit-event', (req, res) => {
  const { eventType, userId, details } = req.body;

  if (!eventType || !userId || !details) {
    return res.status(400).json({ message: 'Missing required fields: eventType, userId, details' });
  }

  const username = req.headers['x-username'] || 'anonymous';
  const requestId = req.headers['x-request-id'] || 'N/A';

  // Log the user-provided audit event data as part of a structured log entry
  logger.info('Audit Event Received', {
    eventType: eventType,
    userId: userId,
    details: details, // User-provided details for the audit event
    ip: req.ip,
    triggeredByUsername: username,
    triggeredByRequestId: requestId,
    source: 'user-generated-audit-endpoint'
  });

  res.status(200).json({ message: 'Audit event logged successfully.' });
});

// Example route
app.get('/', (req, res) => {
  logger.debug('Accessed root path'); // This will only show in console, not in audit.log by default
  res.send('Hello World! Check the console and audit.log for logs.');
});

// Example route that might trigger an error for demonstration
app.get('/error', (req, res, next) => {
  next(new Error('This is a simulated error!'));
});

// Global error handling middleware
app.use((err, req, res, next) => {
  // Log the error using the logger
  logger.error('Unhandled Error', {
    message: err.message,
    stack: err.stack,
    ip: req.ip,
    url: req.originalUrl,
    method: req.method,
    username: req.headers['x-username'] || 'anonymous'
  });
  res.status(500).send('Something broke!');
});

// Start the server
